mapper.sql:
WHERE use_yn = 'Y'

    AND category = #{category}


    AND keyword LIKE CONCAT('%', #{keyword}, '%')

mapper.update:
UPDATE content_filter_word
SET use_yn = 'N', modify_dt = NOW()
WHERE content_filter_word_seq = #{contentFilterWordSeq}

mapper.select:
SELECT COUNT(1)
FROM content_filter_word
WHERE category = #{category}
  AND LOWER(keyword) = LOWER(#{keyword})
  AND use_yn = 'Y'

    AND content_filter_word_seq != #{excludeSeq}
